        travel_time = calculate_time(cur_pos, dest_pos, speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_window

        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        time_window_penalty = max(0, arrival_time - end_window) * 10

        overlap_penalty = calculate_overlap_penalty(dest_pos, used_positions)

        return travel_time, wait_time, time_window_penalty, overlap_penalty

    def calculate_overlap_penalty(dest_pos, used_positions):
        overlap_count = sum(1 for pos in used_positions if np.array_equal(pos, dest_pos))
        return overlap_count * 5

    def modified_cost(travel_time, wait_time, penalty, overlap_penalty, depot_distance):
        return travel_time * 0.5 + wait_time + penalty + overlap_penalty + depot_distance * 0.1

